u_min := -2.1;
u_max := 2.1;
v_min := -1.0;
v_max := 1.0;
A := 1.0;
steps := 250;

float r = A; 

// --- 1. IL TRUCCO DEL WARPING (Riallineamento Punti) ---
// Normalizziamo la griglia da [-2.1, 2.1] a [-1.0, 1.0] in modo sicuro
float t = clamp(u / (2.0 * pi / 3.0), -1.0, 1.0);

// Applichiamo l'easing: il seno rallenta la corsa vicino agli estremi!
// Questa è l'esatta funzione inversa dell'accelerazione che ci rovinava la mesh
t = sin(t * pi / 2.0);

// Riconvertiamo 't' nel nostro safe_u definitivo
float safe_u = t * (2.0 * pi / 3.0);

// --- 2. CALCOLI ---
float safe_v = clamp(v, -1.0, 1.0);
float cos_u = clamp(cos(safe_u) / (1.0 + cos(safe_u)), -1.0, 1.0);
float angle_u = sign(safe_v) * acos(cos_u);

float v_real = abs(safe_v);

// --- 3. COSTRUZIONE GEOMETRIA ---
float x1 = (r / 2.0) + r * cos(safe_u);
float y1 = 0.0;
float z1 = r * sin(safe_u);

float x2 = -(r / 2.0) + r * cos(angle_u);
float y2 = r * sin(angle_u);
float z2 = 0.0;

float final_x = mix(x1, x2, v_real);
float final_y = mix(y1, y2, v_real);
float final_z = mix(z1, z2, v_real);

return vec4(final_x, final_y, final_z, 0.0);//IMG:/home/dioscorid/Projects/presets/textures/Images/linea_30_closed_fullcycle.png
